function minimumDeviation(nums) {
    const pq = new MaxPriorityQueue();
    let min_val = Infinity;

    for (const num of nums) {
        if (num % 2 === 0) {
            pq.enqueue(num);
        } else {
            pq.enqueue(num * 2);
        }
        min_val = Math.min(min_val, num);
    }

    let result = Infinity;
    while (true) {
        const top = pq.dequeue().element;
        result = Math.min(result, top - min_val);

        if (top % 2 === 1) break;
        pq.enqueue(Math.floor(top / 2));
        min_val = Math.min(min_val, Math.floor(top / 2));
    }
    return result;
}
```


    1. Initialize a max priority queue and find the minimum value of the input array.
2. Double the odd number elements in the array and push all the elements into the max priority queue.
3. While the maximum value in the queue is even, divide the maximum value by 2 and push it back into the queue.
4. Calculate the deviation as the difference between the max value and the min value and minimize the result.

